 1	import type { FC } from 'react';
 2	import useGetDeleteAndEditAccessReview from 'src/modules/Providers/hooks/useGetDeleteAndEditAccessReview';
 3	import { ModalHOC } from 'src/modules/Providers/modals/ModalHOC/ModalHOC';
 4	import { hasLiveMigrationProviderType } from 'src/plans/create/utils/hasLiveMigrationProviderType';
 5	
 6	import CreatedAtDetailsItem from '@components/DetailItems/CreatedAtDetailItem';
 7	import NameDetailsItem from '@components/DetailItems/NameDetailItem';
 8	import NamespaceDetailsItem from '@components/DetailItems/NamespaceDetailItem';
 9	import OwnerDetailsItem from '@components/DetailItems/OwnerDetailItem';
10	import { PlanModel, type V1beta1Plan } from '@kubev2v/types';
11	import { DescriptionList } from '@patternfly/react-core';
12	import { FEATURE_NAMES } from '@utils/constants';
13	import { getNamespace } from '@utils/crds/common/selectors';
14	import { useFeatureFlags } from '@utils/hooks/useFeatureFlags';
15	
16	import usePlanSourceProvider from '../../../../hooks/usePlanSourceProvider';
17	
18	import LiveDetailsItem from './components/PlanLive/LiveDetailsItem';
19	import TargetNamespaceDetailsItem from './components/PlanTargetNamespace/TargetNamespaceDetailsItem';
20	import WarmDetailsItem from './components/PlanWarm/WarmDetailsItem';
21	import StatusDetailsItem from './StatusDetailsItem';
22	
23	type DetailsSectionProps = {
24	  plan: V1beta1Plan;
25	};
26	
27	const DetailsSection: FC<DetailsSectionProps> = ({ plan }) => {
28	  const { sourceProvider } = usePlanSourceProvider(plan);
29	  const { isFeatureEnabled } = useFeatureFlags();
30	
31	  const { canPatch } = useGetDeleteAndEditAccessReview({
32	    model: PlanModel,
33	    namespace: getNamespace(plan),
34	  });
35	
36	  const isVsphere = sourceProvider?.spec?.type === 'vsphere';
37	  const isOvirt = sourceProvider?.spec?.type === 'ovirt';
38	  const isLiveMigrationEnabled =
39	    isFeatureEnabled(FEATURE_NAMES.OCP_LIVE_MIGRATION) &&
40	    hasLiveMigrationProviderType(sourceProvider);
41	  return (
42	    <ModalHOC>
43	      <DescriptionList>
44	        <DescriptionList>
45	          <StatusDetailsItem plan={plan} />
46	        </DescriptionList>
47	        <DescriptionList
48	          columnModifier={{
49	            default: '2Col',
50	          }}
51	        >
52	          <NameDetailsItem resource={plan} />
53	          <WarmDetailsItem plan={plan} canPatch={canPatch} shouldRender={isOvirt || isVsphere} />
54	          <LiveDetailsItem plan={plan} canPatch={canPatch} shouldRender={isLiveMigrationEnabled} />
55	          <NamespaceDetailsItem resource={plan} />
56	          <TargetNamespaceDetailsItem plan={plan} canPatch={canPatch} />
57	          <CreatedAtDetailsItem resource={plan} />
58	          <OwnerDetailsItem resource={plan} />
59	        </DescriptionList>
60	      </DescriptionList>
61	    </ModalHOC>
62	  );
63	};
64	
65	export default DetailsSection;

